export default function Home() {
  const [activeSection, setActiveSection] = useState('dashboard')
  const [sidebarOpen, setSidebarOpen] = useState(false)

  const renderContent = () => {
    switch (activeSection) {
      case 'dashboard':
        return (
          <div className="space-y-6">
            <DashboardOverview culturas={defaultCulturas} tarefas={defaultTarefas} />
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              <div className="lg:col-span-2">
                <CropManagement compact culturas={defaultCulturas} />
              </div>
              <div className="space-y-6">
                <WeatherWidget />
                <TasksPanel compact tarefas={defaultTarefas} />
              </div>
            </div>
            <AnalyticsPanel precos={defaultPrecos} />
          </div>
        )
      case 'crops':
        return <CropManagement culturas={defaultCulturas} />
      case 'market':
        return <MarketPrices precos={defaultPrecos} />
      case 'tasks':
        return <TasksPanel tarefas={defaultTarefas} />
      case 'analytics':
        return <AnalyticsPanel precos={defaultPrecos} />
      default:
        return (
          <div className="space-y-6">
            <DashboardOverview culturas={defaultCulturas} tarefas={defaultTarefas} />
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              <div className="lg:col-span-2">
                <CropManagement compact culturas={defaultCulturas} />
              </div>
              <div className="space-y-6">
                <WeatherWidget />
                <TasksPanel compact tarefas={defaultTarefas} />
              </div>
            </div>
            <AnalyticsPanel precos={defaultPrecos} />
          </div>
        )
    }
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-emerald-50 via-white to-amber-50">
      <Sidebar 
        activeSection={activeSection} 
        setActiveSection={setActiveSection}
        isOpen={sidebarOpen}
        setIsOpen={setSidebarOpen}
      />
      
      <div className="lg:pl-72 transition-all duration-300">
        <DashboardHeader 
          onMenuClick={() => setSidebarOpen(!sidebarOpen)}
        />
        
        <main className="p-4 md:p-6 lg:p-8">
          {renderContent()}
        </main>
      </div>
    </div>
  )
}